import { useEffect, useState } from 'react'
import { Plus, Trash2, ChevronDown, ChevronUp } from 'lucide-react'
import type { ProductDetail } from '../../data/productCatalog'
import type { AdminProductInput, ProductAddon } from '../../types/adminProduct'
import { adminCategoryOptions } from '../../services/productService'
import { shopCategoryCheckboxOptions } from '../../data/shopCategories'
import ProductImageUpload from './ProductImageUpload'
import ProductVideoUpload from './ProductVideoUpload'

interface ProductFormProps {
  product?: ProductDetail
  onSave: (input: AdminProductInput) => void
  onCancel: () => void
  error?: string
}

const defaultDetailKeys = [
  'Material',
  'Design Pattern',
  'Occasion',
  'Length',
  'Neckline',
  'Sleeve Length'
]

const emptyForm: AdminProductInput = {
  name: '',
  price: 0,
  image: '',
  categorySlug: adminCategoryOptions[0]?.slug ?? 'one-piece',
  sizes: ['M', 'L', 'XL', '2XL'],
  shortDescription: '',
  description: '',
  sku: '',
  fabric: '',
  productDetails: {},
  addons: [],
}

const inputClass =
  'w-full border border-accent bg-cream px-3 py-2 text-sm outline-none focus:border-maroon'

function genId() {
  return Math.random().toString(36).slice(2, 9)
}

export default function ProductForm({ product, onSave, onCancel, error }: ProductFormProps) {
  const [form, setForm] = useState<AdminProductInput>(emptyForm)
  const [sizesText, setSizesText] = useState('M, L, XL, 2XL')
  const [addons, setAddons] = useState<ProductAddon[]>([])
  const [shopCategoryChecks, setShopCategoryChecks] = useState<Record<string, boolean>>({})

  // Predefined Product Details state
  const [details, setDetails] = useState<Record<string, string>>({
    'Material': '',
    'Design Pattern': '',
    'Occasion': '',
    'Length': '',
    'Neckline': '',
    'Sleeve Length': ''
  })

  // Section collapse states
  const [showDetails, setShowDetails] = useState(false)
  const [showAddons, setShowAddons] = useState(false)
  const [validationError, setValidationError] = useState('')

  useEffect(() => {
    if (product) {
      const checks = Object.fromEntries(
        shopCategoryCheckboxOptions.map((c) => [
          c.id,
          product.shopCategorySelections?.includes(c.id) ?? false,
        ]),
      )
      setShopCategoryChecks(checks)
      setForm({
        name: product.name,
        price: product.price,
        originalPrice: product.originalPrice,
        image: product.image,
        categorySlug: product.categorySlug,
        sizes: product.sizes,
        sku: product.sku ?? '',
        shortDescription: product.shortDescription ?? '',
        description: product.description,
        onSale: product.onSale,
        isNew: product.isNew,
        isBestSeller: product.isBestSeller,
        newArrivalVideo: product.newArrivalVideo,
        fabric: product.fabric ?? '',
        productDetails: product.productDetails ?? {},
        addons: product.addons ?? [],
      })
      setSizesText(product.sizes.join(', '))
      setAddons(product.addons ?? [])
      
      const pDetails = product.productDetails ?? {}
      const initialDetails: Record<string, string> = {}
      defaultDetailKeys.forEach((key) => {
        initialDetails[key] = pDetails[key] ?? ''
      })
      setDetails(initialDetails)
    } else {
      setShopCategoryChecks(
        Object.fromEntries(shopCategoryCheckboxOptions.map((c) => [c.id, false])),
      )
      setForm(emptyForm)
      setSizesText('M, L, XL, 2XL')
      setAddons([])
      setDetails({
        'Material': '',
        'Design Pattern': '',
        'Occasion': '',
        'Length': '',
        'Neckline': '',
        'Sleeve Length': ''
      })
    }
  }, [product])

  const handleChange = (field: keyof AdminProductInput, value: string | number | boolean) => {
    setValidationError('')
    setForm((prev) => {
      const next = { ...prev, [field]: value }
      if (field === 'isNew' && !value) {
        next.newArrivalVideo = undefined
      }
      return next
    })
  }

  /* ── Addon helpers ── */
  const addAddon = () => {
    setAddons((prev) => [
      ...prev,
      { id: genId(), label: '', description: '', price: 0, optional: true },
    ])
  }

  const updateAddon = (id: string, field: keyof ProductAddon, value: string | number | boolean) => {
    setAddons((prev) =>
      prev.map((a) => (a.id === id ? { ...a, [field]: value } : a))
    )
  }

  const removeAddon = (id: string) => {
    setAddons((prev) => prev.filter((a) => a.id !== id))
  }

  const handleDetailChange = (key: string, val: string) => {
    setDetails((prev) => ({ ...prev, [key]: val }))
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (!form.image) return

    if (form.isNew && !form.newArrivalVideo?.trim()) {
      setValidationError('New Arrival video is required when New Arrival is selected.')
      return
    }

    setValidationError('')
    const sizes = sizesText.split(',').map((s) => s.trim()).filter(Boolean)
    const productDetails: Record<string, string> = {}
    defaultDetailKeys.forEach((key) => {
      const val = details[key]?.trim()
      if (val) {
        productDetails[key] = val
      }
    })

    onSave({
      ...form,
      sizes: sizes.length ? sizes : ['M', 'L', 'XL', '2XL'],
      originalPrice: form.originalPrice || undefined,
      fabric: form.fabric?.trim() || undefined,
      newArrivalVideo: form.newArrivalVideo?.trim() || undefined,
      productDetails: Object.keys(productDetails).length ? productDetails : undefined,
      addons: addons.length ? addons : undefined,
      shopCategorySelections: shopCategoryCheckboxOptions
        .map((c) => c.id)
        .filter((id) => shopCategoryChecks[id]),
    })
  }

  return (
    <form onSubmit={handleSubmit} className="border border-accent bg-cream p-6">
      <h2 className="mb-6 font-serif text-lg text-charcoal">
        {product ? 'Edit Product' : 'Add Product'}
      </h2>

      {/* ── Basic Fields ── */}
      <div className="grid gap-4 sm:grid-cols-2">
        <div className="sm:col-span-2">
          <label className="mb-1.5 block text-xs tracking-wide text-charcoal/70 uppercase">Name *</label>
          <input required value={form.name} onChange={(e) => handleChange('name', e.target.value)} className={inputClass} />
        </div>
        <div>
          <label className="mb-1.5 block text-xs tracking-wide text-charcoal/70 uppercase">Price (₹) *</label>
          <input required type="number" min={0} value={form.price || ''} onChange={(e) => handleChange('price', Number(e.target.value))} className={inputClass} />
        </div>
        <div>
          <label className="mb-1.5 block text-xs tracking-wide text-charcoal/70 uppercase">MRP / Original (optional)</label>
          <input type="number" min={0} value={form.originalPrice ?? ''} onChange={(e) => handleChange('originalPrice', e.target.value ? Number(e.target.value) : 0)} className={inputClass} />
        </div>
        <div className="sm:col-span-2">
          <ProductImageUpload value={form.image} onChange={(url) => handleChange('image', url)} />
        </div>
        <div>
          <label className="mb-1.5 block text-xs tracking-wide text-charcoal/70 uppercase">Category *</label>
          <select value={form.categorySlug} onChange={(e) => handleChange('categorySlug', e.target.value)} className={inputClass}>
            {adminCategoryOptions.map((c) => (
              <option key={c.slug} value={c.slug}>{c.label}</option>
            ))}
          </select>
        </div>
        <div>
          <label className="mb-1.5 block text-xs tracking-wide text-charcoal/70 uppercase">Sizes (comma-separated)</label>
          <input value={sizesText} onChange={(e) => setSizesText(e.target.value)} className={inputClass} placeholder="M, L, XL, 2XL" />
        </div>
        <div className="sm:col-span-2">
          <label className="mb-1.5 block text-xs tracking-wide text-charcoal/70 uppercase">Product Code (SKU)</label>
          <input value={form.sku || ''} onChange={(e) => handleChange('sku', e.target.value)} className={inputClass} placeholder="e.g. SK-1002" />
        </div>
        <div className="sm:col-span-2">
          <label className="mb-1.5 block text-xs tracking-wide text-charcoal/70 uppercase">Description</label>
          <textarea rows={4} value={form.description} onChange={(e) => handleChange('description', e.target.value)} className={`${inputClass} resize-none`} />
        </div>
        <label className="flex items-center gap-2 text-sm text-charcoal/70">
          <input type="checkbox" checked={Boolean(form.onSale)} onChange={(e) => handleChange('onSale', e.target.checked)} className="accent-maroon" />
          On Sale
        </label>
        <label className="flex items-center gap-2 text-sm text-charcoal/70">
          <input type="checkbox" checked={Boolean(form.isBestSeller)} onChange={(e) => handleChange('isBestSeller', e.target.checked)} className="accent-maroon" />
          Best Seller
        </label>
        <label className="flex items-center gap-2 text-sm text-charcoal/70">
          <input type="checkbox" checked={Boolean(form.isNew)} onChange={(e) => handleChange('isNew', e.target.checked)} className="accent-maroon" />
          New Arrival
        </label>
        {shopCategoryCheckboxOptions.map((option) => (
          <label key={option.id} className="flex items-center gap-2 text-sm text-charcoal/70">
            <input
              type="checkbox"
              checked={Boolean(shopCategoryChecks[option.id])}
              onChange={(e) =>
                setShopCategoryChecks((prev) => ({ ...prev, [option.id]: e.target.checked }))
              }
              className="accent-maroon"
            />
            {option.label}
          </label>
        ))}
        {form.isNew && (
          <div className="sm:col-span-2">
            <ProductVideoUpload
              required
              value={form.newArrivalVideo ?? ''}
              onChange={(url) => handleChange('newArrivalVideo', url)}
            />
          </div>
        )}
      </div>

      {/* ── Product Details (Predefined fields) ── */}
      <div className="mt-6 border border-accent/60 rounded">
        <button type="button" onClick={() => setShowDetails((o) => !o)} className="flex w-full items-center justify-between px-4 py-3 text-sm font-semibold text-charcoal">
          Product Details
          {showDetails ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
        </button>
        {showDetails && (
          <div className="border-t border-accent/60 px-4 py-4 space-y-4">
            <p className="text-xs text-charcoal/50 font-light">Fill in the values for the following standard product specifications:</p>
            <div className="grid gap-4 sm:grid-cols-2">
              {defaultDetailKeys.map((key) => (
                <div key={key}>
                  <label className="mb-1 block text-[11px] font-semibold text-charcoal/60 uppercase tracking-wider">{key}</label>
                  <input
                    value={details[key] || ''}
                    onChange={(e) => handleDetailChange(key, e.target.value)}
                    className={inputClass}
                    placeholder={`e.g. Enter ${key}`}
                  />
                </div>
              ))}
            </div>
          </div>
        )}
      </div>


      {/* ── Add-ons ── */}
      <div className="mt-3 border border-accent/60 rounded">
        <button type="button" onClick={() => setShowAddons((o) => !o)} className="flex w-full items-center justify-between px-4 py-3 text-sm font-semibold text-charcoal">
          Add-ons (Pant, Dupatta, etc.)
          {showAddons ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
        </button>
        {showAddons && (
          <div className="border-t border-accent/60 px-4 py-4 space-y-4">
            <p className="text-xs text-charcoal/50">Add purchasable extras shown on the product page. Mark as optional to show a checkbox.</p>
            {addons.map((addon) => (
              <div key={addon.id} className="rounded border border-accent/60 p-3 space-y-3">
                <div className="flex items-center justify-between">
                  <span className="text-xs font-semibold text-charcoal/70 uppercase tracking-wide">Add-on</span>
                  <button type="button" onClick={() => removeAddon(addon.id)} className="text-charcoal/40 hover:text-maroon">
                    <Trash2 size={15} />
                  </button>
                </div>
                <div className="grid gap-3 sm:grid-cols-2">
                  <div>
                    <label className="mb-1 block text-xs text-charcoal/60 uppercase">Label *</label>
                    <input value={addon.label} onChange={(e) => updateAddon(addon.id, 'label', e.target.value)} className={inputClass} placeholder="e.g. Add Pant" />
                  </div>
                  <div>
                    <label className="mb-1 block text-xs text-charcoal/60 uppercase">Price (₹) *</label>
                    <input type="number" min={0} value={addon.price || ''} onChange={(e) => updateAddon(addon.id, 'price', Number(e.target.value))} className={inputClass} placeholder="e.g. 1199" />
                  </div>
                  <div className="sm:col-span-2">
                    <label className="mb-1 block text-xs text-charcoal/60 uppercase">Description</label>
                    <input value={addon.description} onChange={(e) => updateAddon(addon.id, 'description', e.target.value)} className={inputClass} placeholder="e.g. Chanderi pant" />
                  </div>
                  <label className="flex items-center gap-2 text-sm text-charcoal/70 sm:col-span-2">
                    <input type="checkbox" checked={addon.optional} onChange={(e) => updateAddon(addon.id, 'optional', e.target.checked)} className="accent-maroon" />
                    Optional (show as checkbox; uncheck = always included)
                  </label>
                </div>
              </div>
            ))}
            <button type="button" onClick={addAddon} className="flex items-center gap-1 text-xs font-semibold text-maroon hover:underline">
              <Plus size={13} /> Add New Add-on
            </button>
          </div>
        )}
      </div>

      {(validationError || error) && (
        <p className="mt-4 text-sm text-gold">{validationError || error}</p>
      )}

      <div className="mt-6 flex gap-3">
        <button
          type="submit"
          disabled={!form.image || (Boolean(form.isNew) && !form.newArrivalVideo?.trim())}
          className="bg-maroon px-6 py-2.5 text-xs font-medium tracking-[0.15em] text-cream uppercase hover:bg-maroon-light disabled:opacity-60"
        >
          Save
        </button>
        <button type="button" onClick={onCancel} className="border border-accent px-6 py-2.5 text-xs font-medium tracking-[0.15em] text-charcoal uppercase hover:border-maroon hover:text-maroon">
          Cancel
        </button>
      </div>
    </form>
  )
}

import { useEffect, useState } from 'react'
import { CheckCircle } from 'lucide-react'
import { useStore } from '../../context/StoreContext'
import { submitContactMessage } from '../../services/contactService'
import type { ContactFormData } from '../../types/contact'

const inputClass =
  'w-full border border-accent bg-cream px-4 py-3 text-sm focus:border-maroon focus:outline-none'

const emptyForm: ContactFormData = {
  firstName: '',
  lastName: '',
  email: '',
  phone: '',
  message: '',
}

export default function ContactForm() {
  const { user } = useStore()
  const [form, setForm] = useState<ContactFormData>(emptyForm)
  const [error, setError] = useState('')
  const [submitted, setSubmitted] = useState(false)
  const [loading, setLoading] = useState(false)

  const handleChange = (field: keyof ContactFormData, value: string) => {
    if (field === 'email' && user) return
    setForm((prev) => ({ ...prev, [field]: value }))
  }

  useEffect(() => {
    if (!user) return
    setForm((prev) => ({ ...prev, email: user.email }))
  }, [user])

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setError('')

    const payload = user ? { ...form, email: user.email } : form

    if (!payload.firstName || !payload.email || !payload.message) {
      setError('Please fill in all required fields.')
      return
    }

    setLoading(true)
    try {
      await submitContactMessage(payload)
      setSubmitted(true)
      setForm(emptyForm)
    } catch {
      setError('Something went wrong. Please try again.')
    } finally {
      setLoading(false)
    }
  }

  if (submitted) {
    return (
      <div className="border border-accent bg-cream-dark/50 p-8 text-center">
        <CheckCircle size={40} className="mx-auto text-maroon" />
        <h3 className="mt-4 font-serif text-xl text-charcoal">Message Sent!</h3>
        <p className="mt-2 text-sm text-charcoal/60">
          Thank you for reaching out. We&apos;ll get back to you shortly.
        </p>
        <button
          onClick={() => setSubmitted(false)}
          className="mt-6 text-xs font-medium tracking-[0.15em] text-maroon uppercase hover:text-maroon-light"
        >
          Send Another Message
        </button>
      </div>
    )
  }

  return (
    <form className="space-y-4" onSubmit={handleSubmit}>
      <div className="grid gap-4 sm:grid-cols-2">
        <div>
          <label className="mb-1.5 block text-xs tracking-wide text-charcoal/70 uppercase">
            First Name *
          </label>
          <input
            required
            type="text"
            value={form.firstName}
            onChange={(e) => handleChange('firstName', e.target.value)}
            className={inputClass}
          />
        </div>
        <div>
          <label className="mb-1.5 block text-xs tracking-wide text-charcoal/70 uppercase">
            Last Name
          </label>
          <input
            type="text"
            value={form.lastName}
            onChange={(e) => handleChange('lastName', e.target.value)}
            className={inputClass}
          />
        </div>
      </div>
      <div>
        <label className="mb-1.5 block text-xs tracking-wide text-charcoal/70 uppercase">
          Email *
        </label>
        <input
          required
          readOnly={Boolean(user)}
          type="email"
          value={user?.email ?? form.email}
          onChange={(e) => handleChange('email', e.target.value)}
          className={`${inputClass} ${user ? 'cursor-not-allowed bg-cream-dark text-charcoal/60' : ''}`}
        />
      </div>
      <div>
        <label className="mb-1.5 block text-xs tracking-wide text-charcoal/70 uppercase">
          Phone No.
        </label>
        <input
          type="tel"
          value={form.phone}
          onChange={(e) => handleChange('phone', e.target.value)}
          className={inputClass}
        />
      </div>
      <div>
        <label className="mb-1.5 block text-xs tracking-wide text-charcoal/70 uppercase">
          Comment or Message *
        </label>
        <textarea
          required
          rows={5}
          value={form.message}
          onChange={(e) => handleChange('message', e.target.value)}
          className={`${inputClass} resize-none`}
        />
      </div>
      {error && <p className="text-sm text-gold">{error}</p>}
      <button
        type="submit"
        disabled={loading}
        className="bg-maroon px-10 py-3.5 text-xs font-medium tracking-[0.2em] text-cream uppercase transition-colors hover:bg-maroon-light disabled:opacity-60"
      >
        {loading ? 'Sending...' : 'Submit'}
      </button>
    </form>
  )
}

import { useEffect, useState } from 'react'
import { Link, useLocation } from 'react-router-dom'
import { Search, Menu, X, ChevronDown, Heart } from 'lucide-react'
import { mainNav, navIcons, brand } from '../../data/navigation'
import { brandAssets } from '../../data/products'
import { useStore } from '../../context/StoreContext'
import HeaderProfileLink from './HeaderProfileLink'
import HeaderCartButton from './HeaderCartButton'

function isNavActive(pathname: string, href?: string, label?: string): boolean {
  if (!href) return false
  if (label === 'COLLECTION') {
    return pathname.startsWith('/dress') || pathname === '/three-piece'
  }
  if (pathname === href) return true
  return pathname.startsWith(`${href}/`)
}

function navDisplayLabel(label: string): string {
  return label
    .toLowerCase()
    .split(' ')
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ')
}

export default function Header() {
  const [mobileOpen, setMobileOpen] = useState(false)
  const [activeDropdown, setActiveDropdown] = useState<string | null>(null)
  const location = useLocation()
  const { wishlistCount, setSearchOpen } = useStore()

  useEffect(() => {
    setMobileOpen(false)
  }, [location.pathname])

  const iconClass = 'text-charcoal/80 transition-colors hover:text-maroon'
  const navLinkClass = (active: boolean) =>
    `flex items-center gap-0.5 whitespace-nowrap text-[13px] transition-colors lg:text-sm ${
      active ? 'text-maroon' : 'text-charcoal/85 hover:text-maroon'
    }`

  const logo = (
    <Link to="/" className="flex shrink-0 flex-col items-center">
      <img
        src={brandAssets.logo}
        alt={brand.name}
        className="h-11 w-auto object-contain md:h-14"
      />
    </Link>
  )

  const navItems = mainNav.map((item) => {
    const Icon = item.icon ? navIcons[item.icon] : null
    const active = isNavActive(location.pathname, item.href, item.label)

    return (
      <div
        key={item.label}
        className="relative"
        onMouseEnter={() => item.children && setActiveDropdown(item.label)}
        onMouseLeave={() => setActiveDropdown(null)}
      >
        <Link to={item.href ?? '/'} className={navLinkClass(active)}>
          {Icon && <Icon size={14} strokeWidth={1.5} />}
          {navDisplayLabel(item.label)}
          {item.children && <ChevronDown size={12} className="mt-px" />}
        </Link>
        {item.children && activeDropdown === item.label && (
          <div className="glass-panel absolute left-1/2 top-full z-50 min-w-[200px] -translate-x-1/2 py-3 shadow-lg">
            {item.children.map((child) => (
              <Link
                key={child.label}
                to={child.href}
                className="block px-5 py-2 text-xs tracking-wide text-charcoal/70 transition-colors hover:bg-white/50 hover:text-maroon"
              >
                {child.label}
              </Link>
            ))}
          </div>
        )}
      </div>
    )
  })

  const actions = (
    <div className="flex items-center gap-4 md:gap-5">
      <button
        onClick={() => setSearchOpen(true)}
        className={iconClass}
        aria-label="Search"
      >
        <Search size={20} strokeWidth={1.5} />
      </button>
      <HeaderProfileLink />
      <Link to="/wishlist" className={`relative ${iconClass}`} aria-label="Wishlist">
        <Heart size={20} strokeWidth={1.5} />
        {wishlistCount > 0 && (
          <span className="absolute -right-2 -top-2 flex h-[18px] min-w-[18px] items-center justify-center rounded-full bg-maroon px-1 text-[10px] font-semibold leading-none text-cream">
            {wishlistCount > 99 ? '99+' : wishlistCount}
          </span>
        )}
      </Link>
      <span className="hidden h-5 w-px bg-accent md:block" aria-hidden />
      <HeaderCartButton />
    </div>
  )

  return (
    <header className="site-header">
      <div className="mx-auto max-w-7xl px-4 pt-3 pb-2 md:px-8 md:pt-3 md:pb-2">
        <div className="relative flex items-center justify-between md:hidden">
          <button
            className="text-charcoal"
            onClick={() => setMobileOpen(!mobileOpen)}
            aria-label="Toggle menu"
          >
            {mobileOpen ? <X size={22} /> : <Menu size={22} />}
          </button>
          <div className="absolute left-1/2 -translate-x-1/2">{logo}</div>
          <div className="flex items-center gap-3">
            <button onClick={() => setSearchOpen(true)} className={iconClass} aria-label="Search">
              <Search size={20} strokeWidth={1.5} />
            </button>
            <HeaderCartButton />
          </div>
        </div>

        <div className="hidden md:block">
          <div className="relative grid grid-cols-[1fr_auto_1fr] items-center">
            <div aria-hidden />
            <div className="justify-self-center">{logo}</div>
            <div className="justify-self-end">{actions}</div>
          </div>

          <nav className="mt-2 flex flex-nowrap items-center justify-center gap-x-4 lg:gap-x-6">
            {navItems}
          </nav>
        </div>
      </div>

      {mobileOpen && (
        <div className="border-t border-accent bg-white px-4 py-4 md:hidden">
          {mainNav.map((item) => {
            const Icon = item.icon ? navIcons[item.icon] : null
            return (
              <div key={item.label}>
                <Link
                  to={item.href ?? '/'}
                  className="flex items-center gap-2 border-b border-accent/60 py-3 text-sm text-charcoal"
                  onClick={() => setMobileOpen(false)}
                >
                  {Icon && <Icon size={14} strokeWidth={1.5} />}
                  {navDisplayLabel(item.label)}
                </Link>
                {item.children?.map((child) => (
                  <Link
                    key={child.label}
                    to={child.href}
                    className="block border-b border-accent/60 py-2.5 pl-4 text-sm text-charcoal/70"
                    onClick={() => setMobileOpen(false)}
                  >
                    {child.label}
                  </Link>
                ))}
              </div>
            )
          })}
          <div className="mt-3 flex gap-6 pt-2">
            <Link
              to="/wishlist"
              className="text-sm text-charcoal/70"
              onClick={() => setMobileOpen(false)}
            >
              Wishlist ({wishlistCount})
            </Link>
            <Link
              to="/account"
              className="text-sm text-charcoal/70"
              onClick={() => setMobileOpen(false)}
            >
              Account
            </Link>
          </div>
        </div>
      )}
    </header>
  )
}

import type { OrderStatus } from '../../types/order'
import { isOrderStatusLocked } from '../../types/order'

const statusStyles: Record<OrderStatus, string> = {
  pending: 'bg-charcoal/10 text-charcoal/70',
  paid: 'bg-maroon/10 text-maroon',
  processing: 'bg-maroon/10 text-maroon',
  shipped: 'bg-gold/15 text-gold',
  delivered: 'bg-green-100 text-green-800',
  cancelled: 'bg-charcoal/10 text-charcoal/50 line-through',
}

interface OrderStatusBadgeProps {
  status: OrderStatus
}

export default function OrderStatusBadge({ status }: OrderStatusBadgeProps) {
  return (
    <span
      className={`inline-block rounded px-2.5 py-1 text-[10px] font-medium tracking-[0.12em] uppercase ${statusStyles[status]}`}
    >
      {status}
      {isOrderStatusLocked(status) && status === 'delivered' ? ' ✓' : ''}
    </span>
  )
}

export function formatOrderStatusLabel(status: OrderStatus): string {
  return status.charAt(0).toUpperCase() + status.slice(1)
}

import { useState, useEffect } from 'react'
import { ChevronLeft, ChevronRight } from 'lucide-react'

interface ProductGalleryProps {
  images: string[]
  name: string
}

export default function ProductGallery({ images, name }: ProductGalleryProps) {
  const [active, setActive] = useState(0)
  const gallery = images.length > 0 ? images : []

  useEffect(() => {
    setActive(0)
  }, [images])

  const prev = () => setActive((a) => (a === 0 ? gallery.length - 1 : a - 1))
  const next = () => setActive((a) => (a === gallery.length - 1 ? 0 : a + 1))

  return (
    <div className="flex gap-3 lg:gap-4">
      {/* Vertical thumbnail strip */}
      {gallery.length > 1 && (
        <div className="hidden w-[72px] shrink-0 flex-col gap-2 sm:flex lg:w-20">
          {gallery.map((img, i) => (
            <button
              key={img + i}
              onClick={() => setActive(i)}
              className={`aspect-[3/4] w-full overflow-hidden border-2 bg-[#f7f5f2] transition-all ${
                i === active
                  ? 'border-maroon opacity-100'
                  : 'border-transparent opacity-60 hover:opacity-90 hover:border-maroon/40'
              }`}
            >
              <img
                src={img}
                alt=""
                className="h-full w-full object-cover object-top"
              />
            </button>
          ))}
        </div>
      )}

      {/* Main image */}
      <div className="relative flex-1">
        <div className="aspect-[3/4] overflow-hidden bg-[#f7f5f2]">
          <img
            src={gallery[active]}
            alt={name}
            className="h-full w-full object-cover object-top transition-opacity duration-300"
          />
        </div>

        {/* Prev/Next arrows on mobile */}
        {gallery.length > 1 && (
          <>
            <button
              onClick={prev}
              className="absolute left-2 top-1/2 -translate-y-1/2 rounded-full bg-white/80 p-1.5 shadow-sm backdrop-blur-sm transition-colors hover:bg-white sm:hidden"
              aria-label="Previous image"
            >
              <ChevronLeft size={18} />
            </button>
            <button
              onClick={next}
              className="absolute right-2 top-1/2 -translate-y-1/2 rounded-full bg-white/80 p-1.5 shadow-sm backdrop-blur-sm transition-colors hover:bg-white sm:hidden"
              aria-label="Next image"
            >
              <ChevronRight size={18} />
            </button>
          </>
        )}

        {/* Image counter badge */}
        {gallery.length > 1 && (
          <span className="absolute bottom-3 right-3 rounded bg-black/40 px-2 py-0.5 text-[10px] text-white backdrop-blur-sm sm:hidden">
            {active + 1}/{gallery.length}
          </span>
        )}

        {/* Mobile dots */}
        {gallery.length > 1 && (
          <div className="mt-3 flex justify-center gap-1.5 sm:hidden">
            {gallery.map((_, i) => (
              <button
                key={i}
                onClick={() => setActive(i)}
                className={`h-1.5 rounded-full transition-all ${
                  i === active ? 'w-4 bg-maroon' : 'w-1.5 bg-maroon/30'
                }`}
                aria-label={`Image ${i + 1}`}
              />
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

import { useState, useMemo } from 'react'
import { Truck, RotateCcw, ChevronDown, ChevronUp, Mail, Phone, Sparkles } from 'lucide-react'
import type { ProductDetail } from '../../data/productCatalog'
import type { ProductAddon } from '../../types/adminProduct'
import { useStore } from '../../context/StoreContext'
import WishlistButton from '../wishlist/WishlistButton'
import { brand } from '../../data/navigation'

interface ProductPurchaseProps {
  product: ProductDetail
}

export default function ProductPurchase({ product }: ProductPurchaseProps) {
  const [size, setSize] = useState(product.sizes[0] ?? 'M')
  const [expanded, setExpanded] = useState(false)
  
  // Accordion states
  const [detailsOpen, setDetailsOpen] = useState(true)
  const [deliveryOpen, setDeliveryOpen] = useState(false)
  const [returnOpen, setReturnOpen] = useState(false)
  const [careOpen, setCareOpen] = useState(false)

  // Addons — each addon has checked state
  const [addonStates, setAddonStates] = useState<Record<string, boolean>>(() => {
    const init: Record<string, boolean> = {}
    product.addons?.forEach((a) => { init[a.id] = false })
    return init
  })

  const { addToCart } = useStore()

  const addons = product.addons ?? []

  const totalPrice = useMemo(() => {
    let t = product.price
    addons.forEach((a) => {
      if (!a.optional || addonStates[a.id]) t += a.price
    })
    return t
  }, [product.price, addons, addonStates])

  const desc = product.description || product.shortDescription || ''
  const showReadMore = desc.length > 120

  const handleAddToCart = () => {
    const selectedAddons = addons
      .filter((a) => !a.optional || addonStates[a.id])
      .map((a) => a.label)
      .join(', ')

    addToCart({
      slug: product.slug,
      name: product.name + (selectedAddons ? ` (+ ${selectedAddons})` : ''),
      image: product.image,
      price: totalPrice,
      size,
      quantity: 1,
    })
  }



  return (
    <div className="flex flex-col gap-6 text-charcoal font-sans">

      {/* Box 1: Product Header (Title, SKU, Description) */}
      <div className="border border-accent/80 bg-[#FAF7F7] p-5 rounded-md shadow-sm">
        <div className="flex items-start justify-between gap-3">
          <div className="flex-1">
            <h1 className="font-serif text-xl md:text-2xl font-semibold tracking-wide text-charcoal leading-snug">
              {product.name}
            </h1>
            <p className="mt-2 text-[10px] font-semibold tracking-widest text-charcoal/40 uppercase">
              Product Code: {product.sku ? product.sku : `SKU-${product.id.toString().slice(0, 8).toUpperCase()}`}
            </p>
          </div>
          <WishlistButton slug={product.slug} className="mt-1 shrink-0" />
        </div>

        {/* Product Description */}
        <div className="mt-4 pt-4 border-t border-accent/40 text-[13px] font-light leading-relaxed text-charcoal/80">
          <p>
            {showReadMore && !expanded
              ? desc.slice(0, 120) + '…'
              : desc}
          </p>
          {showReadMore && (
            <button
              onClick={() => setExpanded((e) => !e)}
              className="mt-1 text-[11px] font-semibold text-maroon underline underline-offset-2 hover:no-underline"
            >
              {expanded ? 'Read Less' : 'Read More'}
            </button>
          )}
        </div>
      </div>

      {/* Box 2: Price Block */}
      <div className="border border-accent/80 bg-white p-5 rounded-md shadow-sm">
        <p className="text-[11px] font-bold text-charcoal/50 uppercase tracking-widest">Regular price</p>
        <p className="font-serif text-2xl font-bold text-maroon mt-1.5">
          MRP ₹{totalPrice.toLocaleString('en-IN')} INR
        </p>
        <p className="text-[10px] font-light text-charcoal/50 mt-1">(Inclusive of all taxes)</p>
      </div>

      {/* Box 3: Size Selector */}
      <div className="bg-white rounded-md shadow-sm">
        <div className="flex items-center gap-3 mb-4 px-1">
          <p className="text-[15px] font-medium text-maroon">Size</p>
          <div className="w-[1px] h-4 bg-maroon/30"></div>
          <button className="text-[14px] font-medium text-maroon underline underline-offset-4 hover:no-underline">
            Size Chart
          </button>
        </div>
        <div className="flex flex-wrap gap-2.5 px-1">
          {product.sizes.map((s) => (
            <button
              key={s}
              onClick={() => setSize(s)}
              className={`min-w-[3rem] h-10 rounded-sm border px-3 py-1.5 text-[14px] font-medium tracking-wide transition-all uppercase shadow-sm ${
                size === s
                  ? 'border-maroon text-maroon bg-white ring-1 ring-maroon'
                  : 'border-accent/40 text-maroon hover:border-maroon hover:shadow bg-white'
              }`}
            >
              {s}
            </button>
          ))}
        </div>
      </div>

      {/* Box 4: Add-ons */}
      {addons.length > 0 && (
        <div className="space-y-4">
          {addons.map((addon) => (
            <AddonCard
              key={addon.id}
              addon={addon}
              checked={addon.optional ? addonStates[addon.id] : true}
              disabled={!addon.optional}
              onChange={(val) =>
                setAddonStates((prev) => ({ ...prev, [addon.id]: val }))
              }
            />
          ))}
        </div>
      )}

      {/* Box 5: Add to Cart & Delivery Info */}
      <div className="flex flex-col gap-4">
        <button
          onClick={handleAddToCart}
          className="flex w-full items-center justify-center gap-2 bg-maroon py-3.5 text-[15px] tracking-wide text-white uppercase transition-colors hover:bg-maroon-light rounded-sm shadow-sm font-medium"
        >
          Add to Cart
        </button>
        
        <div className="flex justify-center items-center gap-2.5 text-sm font-semibold text-maroon pt-1">
          <Truck size={18} className="shrink-0" />
          <span>Estimated Delivery 7-9 working days after the order.</span>
        </div>
      </div>

      {/* Box 6: Accordions Group */}
      <div className="flex flex-col gap-4 bg-white rounded-md p-4 shadow-sm border border-accent/40 mt-2">
        
        {/* Product Details accordion */}
        <div className="border border-accent/40 rounded-sm">
          <button
            onClick={() => setDetailsOpen((o) => !o)}
            className="flex w-full items-center justify-between px-4 py-3.5 text-[15px] font-bold text-maroon hover:bg-[#FAF7F7] transition-colors"
          >
            Product Details
            {detailsOpen ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
          </button>
          {detailsOpen && (
            <div className="px-4 pb-4 pt-2">
              <div className="grid grid-cols-2 gap-x-8 gap-y-4 text-[14px]">
                {['Material', 'Design Pattern', 'Occasion', 'Length', 'Neckline', 'Sleeve Length'].map((key) => {
                  const val = product.productDetails?.[key] || (key === 'Material' ? product.fabric : '')
                  if (!val) return null
                  return (
                    <div key={key} className="flex justify-between items-end border-b border-maroon/40 pb-2">
                      <span className="text-maroon font-medium">{key}</span>
                      <span className="text-charcoal/90 text-right">{val}</span>
                    </div>
                  )
                })}
              </div>
            </div>
          )}
        </div>

        {/* Delivery & Payment accordion */}
        <div className="border border-accent/40 rounded-sm mt-2">
          <button
            onClick={() => setDeliveryOpen((o) => !o)}
            className="flex w-full items-center justify-between px-4 py-3.5 text-[15px] font-bold text-maroon hover:bg-[#FAF7F7] transition-colors"
          >
            Delivery & Payment
            {deliveryOpen ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
          </button>
          {deliveryOpen && (
            <div className="px-4 pb-4 pt-2 text-[14px] text-charcoal/80 leading-relaxed space-y-3 font-medium">
              <p>All of our products are made to order, crafted after we receive your request. Most items feature intricate handwork, such as painting, embroidery, or other embellishments.</p>
              <p>As a result, we typically dispatch products 7-9 working days after the order. Transit times vary from 2-5 days depending on the destination.</p>
              <p className="font-semibold text-maroon">Cash on Delivery (COD) available</p>
              <p className="font-semibold text-maroon">Before delivery & alteration need full payment.</p>
            </div>
          )}
        </div>

        {/* Return & Exchange accordion */}
        <div className="border border-accent/40 rounded-sm mt-2">
          <button
            onClick={() => setReturnOpen((o) => !o)}
            className="flex w-full items-center justify-between px-4 py-3.5 text-[15px] font-bold text-maroon hover:bg-[#FAF7F7] transition-colors"
          >
            Return & Exchange
            {returnOpen ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
          </button>
          {returnOpen && (
            <div className="px-4 pb-4 pt-2 text-[14px] text-charcoal/80 font-medium space-y-3">
              <div className="flex items-start gap-2.5">
                <RotateCcw size={16} className="text-maroon shrink-0 mt-0.5" />
                <p>3 days no-questions-asked Returns/Exchange</p>
              </div>
              <div className="flex items-start gap-2.5">
                <RotateCcw size={16} className="text-maroon shrink-0 mt-0.5" />
                <p>Free pickup for Returns/Exchanges</p>
              </div>
              <div className="flex items-start gap-2.5">
                <RotateCcw size={16} className="text-maroon shrink-0 mt-0.5" />
                <p>Exchanges not limited to size adjustments, offered on any product</p>
              </div>
              <div className="flex items-start gap-2.5">
                <RotateCcw size={16} className="text-maroon shrink-0 mt-0.5" />
                <p>International/Customized orders not eligible for Returns/Exchanges</p>
              </div>
              <div className="flex items-start gap-2.5">
                <RotateCcw size={16} className="text-maroon shrink-0 mt-0.5" />
                <p>Returns/Exchanges allowed only for unused products with tags</p>
