        <div className="border border-accent/40 rounded-sm mt-2">
          <button
            onClick={() => setCareOpen((o) => !o)}
            className="flex w-full items-center justify-between px-4 py-3.5 text-[15px] font-bold text-maroon hover:bg-[#FAF7F7] transition-colors"
          >
            Care Instruction
            {careOpen ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
          </button>
          {careOpen && (
            <div className="px-4 pb-4 pt-2 text-[14px] text-charcoal/80 font-medium space-y-3">
              <div className="flex items-start gap-2.5">
                <Sparkles size={16} className="text-maroon shrink-0 mt-0.5" />
                <p>Hand wash in cold water with a mild detergent</p>
              </div>
              <div className="flex items-start gap-2.5">
                <Sparkles size={16} className="text-maroon shrink-0 mt-0.5" />
                <p>Dry Clean recommended for Sarees</p>
              </div>
              <div className="flex items-start gap-2.5">
                <Sparkles size={16} className="text-maroon shrink-0 mt-0.5" />
                <p>Wash inside out to prevent fading</p>
              </div>
              <div className="flex items-start gap-2.5">
                <Sparkles size={16} className="text-maroon shrink-0 mt-0.5" />
                <p>Iron on low heat, avoiding embellishments, painting or embroidery</p>
              </div>
            </div>
          )}
        </div>

      </div>

      {/* Box 7: Contact & Boutique */}
      <div className="border border-accent/80 bg-white p-5 rounded-md shadow-sm divide-y divide-accent/40">

        <div className="pb-5">
          <h3 className="text-xs font-bold tracking-widest uppercase mb-3 text-charcoal/80">Contact Us</h3>
          <div className="space-y-3 text-[13px] text-charcoal/70 font-light leading-relaxed">
            <p className="font-medium text-charcoal">Find our location. Visit Our Store</p>
            <p className="flex items-center gap-2">
              <Phone size={13} className="text-maroon shrink-0" />
              <a href={`tel:${brand.phone.replace(/\s/g, '')}`} className="text-maroon font-medium hover:underline">
                {brand.phone}
              </a>
            </p>
            <p className="flex items-center gap-2">
              <Mail size={13} className="text-maroon shrink-0" />
              <a href={`mailto:${brand.email}`} className="text-maroon font-medium hover:underline">
                {brand.email}
              </a>
            </p>
          </div>
        </div>

        <div className="pt-5">
          <h3 className="text-xs font-bold tracking-widest uppercase mb-3 text-charcoal/80">Our Boutique</h3>
          <div className="space-y-2 text-[13px] text-charcoal/70 font-light leading-relaxed">
            <p>
              <strong className="font-semibold text-charcoal">Address:</strong>{' '}
              {brand.address}
            </p>
            <p>
              <strong className="font-semibold text-charcoal">Hours:</strong>{' '}
              {brand.hours}
            </p>
          </div>
        </div>

      </div>

    </div>
  )
}

/* ── Addon Card sub-component ── */
interface AddonCardProps {
  addon: ProductAddon
  checked: boolean
  disabled: boolean
  onChange: (val: boolean) => void
}

function AddonCard({ addon, checked, disabled, onChange }: AddonCardProps) {
  return (
    <label
      className={`flex cursor-pointer flex-col p-4 rounded-md border transition-all shadow-sm ${
        checked
          ? 'border-maroon bg-maroon/5'
          : 'border-accent/80 bg-white hover:border-maroon/40'
      } ${disabled ? 'cursor-default' : ''}`}
    >
      <div className="flex items-start gap-3">
        {addon.optional && (
          <input
            type="checkbox"
            checked={checked}
            onChange={(e) => onChange(e.target.checked)}
            className="mt-1 h-4 w-4 accent-maroon shrink-0"
          />
        )}
        <div className="flex-1">
          <p className="text-xs font-bold tracking-wider text-charcoal uppercase">{addon.label}</p>
          <p className="text-[13px] text-charcoal/60 mt-1 font-light leading-relaxed">{addon.description}</p>
          <div className="mt-3 pt-2.5 border-t border-accent/30 flex items-center justify-between">
            <div>
              <p className="text-[11px] font-semibold text-maroon uppercase tracking-wide">
                MRP ₹{addon.price.toLocaleString('en-IN')} INR
              </p>
              <p className="text-[9px] font-light text-charcoal/40">(Inclusive of all taxes)</p>
            </div>
            {addon.optional && (
              <span className={`text-[10px] font-semibold uppercase tracking-wider px-2 py-0.5 rounded ${checked ? 'text-maroon bg-maroon/10' : 'text-charcoal/40'}`}>
                {checked ? 'Added' : 'Add Optional'}
              </span>
            )}
          </div>
        </div>
      </div>
    </label>
  )
}

import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { CheckCircle, RotateCcw } from 'lucide-react'
import type { Order } from '../../types/order'
import type { ReturnRequest } from '../../types/return'
import { RETURN_REASONS } from '../../data/returns'
import { createReturnRequest, fetchReturnByOrderId } from '../../services/returnService'
import {
  getEligibilityMessage,
  getReturnDaysLeft,
  getReturnEligibility,
} from '../../utils/returnEligibility'
import ReturnStatusBadge from './ReturnStatusBadge'
import ReturnStatusStepper from './ReturnStatusStepper'

interface ReturnRequestButtonProps {
  order: Order
  email: string
  onRequested?: () => void
}

export default function ReturnRequestButton({ order, email, onRequested }: ReturnRequestButtonProps) {
  const [open, setOpen] = useState(false)
  const [reason, setReason] = useState('')
  const [details, setDetails] = useState('')
  const [error, setError] = useState('')
  const [existing, setExisting] = useState<ReturnRequest | undefined>()
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let cancelled = false
    setLoading(true)
    fetchReturnByOrderId(order.id, email).then((request) => {
      if (!cancelled) {
        setExisting(request)
        setLoading(false)
      }
    })
    return () => {
      cancelled = true
    }
  }, [order.id, email])

  const eligibility = getReturnEligibility(order, existing)
  const daysLeft = getReturnDaysLeft(order)
  const message = getEligibilityMessage(eligibility, daysLeft)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!reason) {
      setError('Please select a reason for the return.')
      return
    }
    const fullReason = details.trim() ? `${reason}: ${details.trim()}` : reason
    const created = await createReturnRequest({ orderId: order.id, email, reason: fullReason })
    if (!created) {
      const found = await fetchReturnByOrderId(order.id, email)
      if (found) {
        setExisting(found)
        setOpen(false)
        return
      }
      setError('Could not submit return request. Please try again.')
      return
    }
    setExisting(created)
    setOpen(false)
    onRequested?.()
  }

  if (loading) {
    return (
      <div className="mt-4 border-t border-accent pt-4">
        <p className="text-xs text-charcoal/40">Checking return status...</p>
      </div>
    )
  }

  if (eligibility === 'submitted' && existing) {
    return (
      <div className="mt-4 space-y-3 border-t border-accent pt-4">
        <div className="flex items-start gap-2 text-maroon">
          <CheckCircle size={16} className="mt-0.5 shrink-0" />
          <div className="w-full">
            <p className="text-sm font-medium text-charcoal">Return request submitted</p>
            <p className="mt-1 text-xs text-charcoal/50">
              We&apos;ll review within 48 hours. Refund in 7–10 days after pickup.
            </p>
          </div>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <span className="text-xs text-charcoal/50">Return status:</span>
          <ReturnStatusBadge status={existing.status} />
        </div>
        <ReturnStatusStepper status={existing.status} />
        <Link
          to="/account/returns"
          className="inline-block text-[10px] font-medium tracking-[0.1em] text-maroon uppercase hover:text-maroon-light"
        >
          View details
        </Link>
      </div>
    )
  }

  return (
    <div className="mt-4 border-t border-accent pt-4">
      <p className={`text-xs ${eligibility === 'eligible' ? 'text-maroon' : 'text-charcoal/50'}`}>
        {message}
      </p>

      {eligibility === 'eligible' && (
        <>
          {!open ? (
            <button
              type="button"
              onClick={() => setOpen(true)}
              className="mt-3 flex items-center gap-2 bg-maroon px-4 py-2 text-[10px] font-medium tracking-[0.15em] text-cream uppercase transition-colors hover:bg-maroon-light"
            >
              <RotateCcw size={14} />
              Return / Exchange
            </button>
          ) : (
            <form onSubmit={handleSubmit} className="mt-4 space-y-3">
              <div>
                <label className="mb-2 block text-xs font-medium tracking-[0.1em] text-charcoal uppercase">
                  Reason *
                </label>
                <select
                  value={reason}
                  onChange={(e) => { setReason(e.target.value); setError('') }}
                  className="w-full border border-accent bg-cream px-3 py-2 text-sm text-charcoal outline-none focus:border-maroon"
                >
                  <option value="">Select a reason</option>
                  {RETURN_REASONS.map((r) => (
                    <option key={r} value={r}>{r}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="mb-2 block text-xs font-medium tracking-[0.1em] text-charcoal uppercase">
                  Additional details (optional)
                </label>
                <textarea
                  rows={2}
                  value={details}
                  onChange={(e) => setDetails(e.target.value)}
                  className="w-full resize-none border border-accent px-3 py-2 text-sm outline-none focus:border-maroon"
                  placeholder="Any extra information..."
                />
              </div>
              {error && <p className="text-xs text-gold">{error}</p>}
              <div className="flex flex-wrap gap-3">
                <button
                  type="submit"
                  className="bg-maroon px-4 py-2 text-[10px] font-medium tracking-[0.15em] text-cream uppercase hover:bg-maroon-light"
                >
                  Submit Request
                </button>
                <button
                  type="button"
                  onClick={() => { setOpen(false); setError('') }}
                  className="px-4 py-2 text-[10px] font-medium tracking-[0.15em] text-charcoal/50 uppercase hover:text-charcoal"
                >
                  Cancel
                </button>
              </div>
              <p className="text-[10px] text-charcoal/40">
                Unused items with tags.{' '}
                <Link to="/contact-us" className="text-maroon hover:text-maroon-light">
                  Read return policy
                </Link>
              </p>
            </form>
          )}
        </>
      )}

      {eligibility === 'window_closed' && (
        <Link
          to="/contact-us"
          className="mt-2 inline-block text-[10px] font-medium tracking-[0.1em] text-maroon uppercase hover:text-maroon-light"
        >
          Read return policy
        </Link>
      )}
    </div>
  )
}

